import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import WhiteLabelCryptoScreen from "@screens/whitelabel-crypto";
// import ContactUs from "@components/common/move-forward";
// import Faq from "@components/common/faq";
import { useLocation } from "@reach/router";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";
import Layout_v2 from "@components/layout_v2";

const WazirxCloneScript = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "White-Label Crypto Exchange Development", link: null },
  ];
  // const WhiteLabelFaq = [
  //   {
  //     question: "What is a cryptocurrency exchange?",
  //     answer:
  //       "A crypto exchange is a platform where users can buy, sell, and trade various digital currencies.",
  //   },
  //   {
  //     question:
  //       "Can you explain the concept of a White-label cryptocurrency exchange?",
  //     answer:
  //       "It's a pre-built solution that lets you launch your own branded crypto exchange platform quickly.",
  //   },
  //   {
  //     question:
  //       "How quickly can a crypto exchange be launched using your White-label exchange script?",
  //     answer: "Our efficient script gets you up and running in weeks.",
  //   },
  //   {
  //     question:
  //       "Is there a significant cost associated with launching a crypto exchange using your script?",
  //     answer:
  //       "No! Our solution is cost-effective, making crypto exchange ownership accessible.",
  //   },
  //   {
  //     question:
  //       "Is your White-label crypto exchange software known for its security features?",
  //     answer:
  //       "Absolutely! We use robust security measures to keep your users' funds safe.",
  //   },
  //   {
  //     question:
  //       "Do you offer custom development services for cryptocurrency exchanges?",
  //     answer:
  //       "Yes! We can develop a cryptocurrency exchange from the ground up as required.",
  //   },
  // ];

  const { data } = props;
  const fileUrl =
    data?.whiteLabelImg?.childImageSharp?.gatsbyImageData?.images?.fallback
      ?.src;
  const validData = data?.allMetaJson?.nodes[0];
  const location = useLocation();

  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "White-label crypto exchange development lets you launch a ready-made, customizable crypto trading platform quickly with your brand and features.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1606",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What is a White-Label Crypto Exchange and How Does It Work?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "A White-Label Crypto Exchange is a pre-built trading platform you brand and launch, with all core functions ready for users to trade crypto.",
            },
          },
          {
            "@type": "Question",
            name: "What are the Benefits of Using a White-Label Solution?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "It offers fast launch, lower development cost, customizable branding, ready-to-use features, and reduced technical complexity.",
            },
          },
          {
            "@type": "Question",
            name: "Is a white-label crypto exchange legal? ",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Yes, a white-label crypto exchange is legal as long as it complies with the regulations and licensing requirements of the country where it operates.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      />
      <BreadCrumbV2 items={breadcrumbLinks} />
      <WhiteLabelCryptoScreen />
      {/* <Faq faqData={WhiteLabelFaq} />
      <ContactUs db={db} /> */}
    </Layout_v2>
  );
};

export default WazirxCloneScript;

export const queryData = graphql`
  query MyQuery {
    whiteLabelImg: file(relativePath: { eq: "white-label-crypto.png" }) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(
      filter: { slug: { eq: "white-label-crypto-exchange-development" } }
    ) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
